changeSet.sql:
-- Временно снимаем NOT NULL constraint чтобы безопасно заменить статусы
ALTER TABLE orders ALTER COLUMN status_id DROP NOT NULL;

-- Обнуляем status_id у заказов со старыми статусами
UPDATE orders SET status_id = NULL
WHERE status_id IN (
    SELECT id FROM order_statuses WHERE is_system = true
);

-- Удаляем старые системные статусы
DELETE FROM order_statuses WHERE is_system = true;

-- Вставляем новые статусы под интеграцию с магазином
INSERT INTO order_statuses (id, code, name, color, sort_order, is_final, is_system) VALUES
('10000000-0000-0000-0000-000000000011', 'NEW',       'Новый',        '#3b82f6', 1, false, true),
('10000000-0000-0000-0000-000000000012', 'PICKING',   'Комплектуется','#f59e0b', 2, false, true),
('10000000-0000-0000-0000-000000000013', 'SHIPPED',   'Отправлен',    '#8b5cf6', 3, false, true),
('10000000-0000-0000-0000-000000000014', 'DELIVERED', 'Получен',      '#22c55e', 4, true,  true),
('10000000-0000-0000-0000-000000000015', 'ARCHIVED',  'Архив',        '#6b7280', 5, true,  true);

-- Присваиваем статус NEW всем заказам с пустым status_id
UPDATE orders SET status_id = '10000000-0000-0000-0000-000000000011'
WHERE status_id IS NULL;

-- Восстанавливаем NOT NULL constraint
ALTER TABLE orders ALTER COLUMN status_id SET NOT NULL;
